const require_findAyahIdBySurah = require('./findAyahIdBySurah.cjs');
const require_findSurahAyahByAyahId = require('./findSurahAyahByAyahId.cjs');

//#region src/nextAyah.ts
/**
* Get the next ayah for the given surah and ayah number.
* @param surah - The surah number.
* @param ayah - The ayah number within the surah.
* @param data - The Lists object containing SurahList.
* @returns The surah and ayah number of the next ayah.
*/
function nextAyah(surah, ayah, data) {
	if (surah < 1 || surah > data.meta.numSurahs) throw new RangeError("Surah must be between 1 and " + data.meta.numSurahs);
	const ayahId = require_findAyahIdBySurah.findAyahIdBySurah(surah, ayah, data);
	return require_findSurahAyahByAyahId.findSurahAyahByAyahId(ayahId == data.meta.numAyahs ? 1 : ayahId + 1, data);
}

//#endregion
exports.nextAyah = nextAyah;